+    function validateCoverageArtifact(matrix) {
+      const families = Array.isArray(matrix?.feature_families) ? matrix.feature_families : [];
+      const scenarios = Array.isArray(matrix?.scenarios) ? matrix.scenarios : [];
+      const scenarioIds = new Set(scenarios.map((entry) => entry.id));
+
+      if (families.length === 0 || scenarios.length === 0) {
+        return {
+          ok: false,
+          reason: "missing feature families or scenarios"
+        };
+      }
+
+      for (const family of families) {
+        if (!Array.isArray(family.scenario_ids) || family.scenario_ids.length === 0) {
+          return {
+            ok: false,
+            reason: `family ${family.id || "unknown"} has no scenario ids`
+          };
+        }
+        for (const scenarioId of family.scenario_ids) {
+          if (!scenarioIds.has(scenarioId)) {
+            return {
+              ok: false,
+              reason: `family ${family.id || "unknown"} references missing scenario ${scenarioId}`
+            };
+          }
+        }
+      }
+
+      return { ok: true };
+    }
